import Foundation
import UIKit

// MARK: - Constants

let BASE_URL = "https://api.example.com"
let API_KEY = "YOUR_API_KEY"

// MARK: - Models

struct Stock {
    let symbol: String
    let name: String
    let price: Double
}

struct Trade {
    let stock: Stock
    let quantity: Int
    let type: String // buy/sell
}

struct Portfolio {
    var stocks: [Stock] = []
    var cash: Double = 0.0
}

// MARK: - API Communication

class APIClient {
    func executeTrade(trade: Trade, completion: @escaping (Result<Bool, Error>) -> Void) {
        guard let url = URL(string: "\(BASE_URL)/trade") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("Bearer \(API_KEY)", forHTTPHeaderField: "Authorization")
        
        do {
            let jsonEncoder = JSONEncoder()
            let jsonData = try jsonEncoder.encode(trade)
            request.httpBody = jsonData
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else { return }
            do {
                let jsonDecoder = JSONDecoder()
                let result = try jsonDecoder.decode(TradeResult.self, from: data)
                
                switch result.status {
                case .success:
                    completion(.success(true))
                case .failure(let error):
                    completion(.failure(error))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}

struct TradeResult: Codable {
    let status: Status
}

enum Status: String, Codable {
    case success
    case failure(String)
}

// MARK: - Portfolio Management

class PortfolioManager {
    var portfolio: Portfolio
    
    init(portfolio: Portfolio = Portfolio()) {
        self.portfolio = portfolio
    }
    
    func addStock(stock: Stock) {
        portfolio.stocks.append(stock)
    }
    
    func removeStock(stock: Stock) {
        if let index = portfolio.stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            portfolio.stocks.remove(at: index)
        }
    }
}

// MARK: - Trading Functionality

class Trader {
    var portfolioManager: PortfolioManager
    var apiClient: APIClient
    
    init(portfolioManager: PortfolioManager = PortfolioManager(), apiClient: APIClient = APIClient()) {
        self.portfolioManager = portfolioManager
        self.apiClient = apiClient
    }
    
    func executeTrade(trade: Trade) {
        apiClient.executeTrade(trade: trade) { [weak self] result in
            switch result {
            case .success:
                self?.portfolioManager.addStock(stock: trade.stock)
            case .failure(let error):
                print("Error executing trade: \(error)")
            }
        }
    }
}

// MARK: - Example Usage

let trader = Trader()
let portfolioManager = PortfolioManager()

let stock1 = Stock(symbol: "AAPL", name: "Apple Inc.", price: 100.0)
let stock2 = Stock(symbol: "GOOG", name: "Alphabet Inc.", price: 2000.0)

trader.executeTrade(trade: Trade(stock: stock1, quantity: 10, type: "buy"))
trader.executeTrade(trade: Trade(stock: stock2, quantity: 5, type: "sell"))

print("Portfolio: \(portfolioManager.portfolio.stocks)")